const res = $input.first().json;
const rows = res.values || [];
let found = null;
for (let i = 0; i < rows.length; i++) {
  const s = (rows[i][4] || '').toString().toUpperCase().trim();
  if (s === 'PENDING') { found = { idx: i, row: rows[i] }; break; }
}
if (!found) throw new Error('No PENDING topic in Dashboard tab. Set STATUS (col E) = PENDING for a row.');
const sheetRow   = found.idx + 4;
const topic      = (found.row[1] || '').trim();
const difficulty = (found.row[2] || 'beginner').trim();
const durationMin = parseFloat(found.row[3]) || 1;
if (!topic) throw new Error('PENDING row found but Topic (col B) is empty.');
const jobId = (found.row[0] || '').trim() || ('PHY-' + Date.now().toString().slice(-8));
console.log('Row ' + sheetRow + ' | ' + jobId + ' | ' + topic + ' | ' + durationMin + 'min');
return [{ json: { job_id: jobId, topic: topic, difficulty: difficulty, duration_min: durationMin, sheet_row: sheetRow, source: 'google_sheet' } }];

const raw  = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;

let sheetData = {};
try { sheetData = $('Pick PENDING Topic').first().json; } catch(e) {}

const jobId    = body.job_id    || raw.job_id    || sheetData.job_id    || ('PHY-' + Date.now().toString().slice(-8));
const topic    = body.topic     || raw.topic     || sheetData.topic;
const sheetRow = body.sheet_row || raw.sheet_row || sheetData.sheet_row || null;

if (!topic) throw new Error('No topic found. Add a PENDING row in Google Sheet Dashboard (col B=topic, col E=PENDING).');

return [{ json: { job_id: jobId, topic: topic, sheet_row: sheetRow, start_time: Date.now() } }];

const data = $input.first().json;

const prompt = `You are a script writer for a physics YouTube Shorts channel.
Topic: ${data.topic}

Write a 20-25 second engaging script for a vertical (9:16) physics YouTube Short.
Return ONLY a raw JSON object with no markdown fences:
{
  "narration": "50-70 word narration text. Engaging, educational, conversational. No jargon.",
  "clip_prompts": [
    "Detailed Seedance video generation prompt for clip 1, cinematic 9:16 vertical physics visual, ~80 chars vivid description",
    "Detailed Seedance video generation prompt for clip 2, cinematic 9:16 vertical physics visual, ~80 chars vivid description",
    "Detailed Seedance video generation prompt for clip 3, cinematic 9:16 vertical physics visual, ~80 chars vivid description"
  ],
  "title": "Short punchy YouTube title under 60 chars",
  "hashtags": "#physics #science #shorts #learn"
}

REQUIREMENTS:
- narration: exactly 50-70 words, spoken naturally, hooks viewer immediately
- clip_prompts: exactly 3 strings, each describing a physics-themed cinematic visual for 9:16 vertical video, be vivid and specific
- title: punchy, curiosity-inducing, under 60 characters
- hashtags: 4-6 relevant hashtags as a single string`;

return [{ json: { ...data, gemini_script_request: {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: { maxOutputTokens: 2048, temperature: 0.8, responseMimeType: 'application/json', thinkingConfig: { thinkingBudget: 0 } }
} } }];

const response  = $input.first().json;
const jobConfig = $('Set Job Config').first().json;

if (!response.candidates || !response.candidates[0] || !response.candidates[0].content) {
  throw new Error('Gemini script response empty: ' + JSON.stringify(response).slice(0, 300));
}

let rawText = response.candidates[0].content.parts[0].text.trim();
rawText = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

let parsed;
try { parsed = JSON.parse(rawText); } catch(e1) {
  const start = rawText.indexOf('{'), end = rawText.lastIndexOf('}');
  const block = (start !== -1 && end !== -1) ? rawText.slice(start, end + 1) : rawText;
  try { parsed = JSON.parse(block); } catch(e2) {
    throw new Error('Failed to parse script JSON: ' + rawText.slice(0, 500));
  }
}

if (!parsed.narration) throw new Error('Response missing narration field');
if (!Array.isArray(parsed.clip_prompts) || parsed.clip_prompts.length !== 3) {
  throw new Error('Response must have clip_prompts array of exactly 3 items. Got: ' + JSON.stringify(parsed.clip_prompts));
}

console.log('Script generated. Narration words: ' + parsed.narration.split(' ').length);
console.log('Clip prompts: ' + parsed.clip_prompts.length);

return [{
  json: {
    ...jobConfig,
    narration: parsed.narration,
    clip_prompts: parsed.clip_prompts,
    title: parsed.title || jobConfig.topic,
    hashtags: parsed.hashtags || '#physics #science #shorts'
  }
}];

const https = require('https');
const fs = require('fs');

const data = $input.first().json;
const apiKey = $env.ELEVENLABS_API_KEY;
const voiceId = $env.ELEVENLABS_VOICE_ID;
const jobId = data.job_id;

function httpsPost(hostname, path, headers, bodyStr) {
  return new Promise((resolve, reject) => {
    const buf = Buffer.from(bodyStr, 'utf-8');
    const req = https.request({ hostname, path, method: 'POST', headers: { ...headers, 'Content-Length': buf.length } }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve({ status: res.statusCode, body: Buffer.concat(chunks).toString() }));
    });
    req.on('error', reject);
    req.write(buf);
    req.end();
  });
}

const body = JSON.stringify({
  text: data.narration,
  model_id: 'eleven_multilingual_v2',
  voice_settings: { stability: 0.5, similarity_boost: 0.8 }
});

const res = await httpsPost('api.elevenlabs.io', '/v1/text-to-speech/' + voiceId + '/with-timestamps', {
  'Content-Type': 'application/json',
  'xi-api-key': apiKey
}, body);

if (res.status !== 200) throw new Error('ElevenLabs error ' + res.status + ': ' + res.body);

const result = JSON.parse(res.body);
const { audio_base64, alignment } = result;

// Save audio
const inputDir = '/data/ffmpeg/input';
if (!require('fs').existsSync(inputDir)) require('fs').mkdirSync(inputDir, { recursive: true });
const audioPath = '/data/ffmpeg/input/' + jobId + '_narration.mp3';
fs.writeFileSync(audioPath, Buffer.from(audio_base64, 'base64'));

// Build word-level subtitle chunks
const chars = alignment.characters;
const starts = alignment.character_start_times_seconds;
const durs = alignment.character_durations_seconds;
const totalDuration = starts[starts.length - 1] + durs[durs.length - 1];

const words = [];
let wChars = '', wStart = null, wEnd = 0;
for (let i = 0; i < chars.length; i++) {
  if (chars[i] === ' ' || chars[i] === '\n') {
    if (wChars.trim()) words.push({ text: wChars.trim(), start: wStart, end: wEnd });
    wChars = ''; wStart = null;
  } else {
    if (wStart === null) wStart = starts[i];
    wEnd = starts[i] + durs[i];
    wChars += chars[i];
  }
}
if (wChars.trim()) words.push({ text: wChars.trim(), start: wStart, end: wEnd });

const chunks = [];
const PER = 5;
for (let i = 0; i < words.length; i += PER) {
  const g = words.slice(i, i + PER);
  chunks.push({ text: g.map(w => w.text).join(' '), start: g[0].start, end: g[g.length-1].end + 0.1 });
}

const subsPath = '/data/ffmpeg/input/' + jobId + '_subs.json';
fs.writeFileSync(subsPath, JSON.stringify(chunks));

return [{ json: { ...data, audio_path: audioPath, subs_path: subsPath, audio_duration: totalDuration, subtitle_chunks: chunks } }];
